local b64decode = (crypt and crypt.base64 and crypt.base64.decode) or (crypt and crypt.base64decode) or base64_decode

if getcustomasset and writefile and isfile and b64decode then

    -- 👇👇👇 PASTE YOUR GENERAL FONT BASE64 STRING HERE 👇👇👇
    local generalFontDataRaw = [[]]
    -- 👆👆👆 END OF GENERAL FONT BASE64 STRING 👆👆👆

    -- 👇👇👇 PASTE YOUR FORTNITE FONT BASE64 STRING HERE 👇👇👇
    local fortniteFontDataRaw = [[

]]
    -- 👆👆👆 END OF FORTNITE FONT BASE64 STRING 👆👆👆

    local function processFont(rawData, fName, cName, familyName)
        rawData = rawData:gsub("[^%w%+/=]", "")
        if #rawData > 100 then
            if not isfile(fName) then
                local success, decoded = pcall(b64decode, rawData)
                if success and decoded then
                    writefile(fName, decoded)
                else
                    warn("[Phantom] Base64 decoding failed for " .. familyName .. ". Please check your string format.")
                    return nil
                end
            end
            if not isfile(cName) and isfile(fName) then
                local fontJson = [[{"name": "]]..familyName..[[","faces": [{"name": "Regular","weight": 400,"style": "normal","assetId": "]] .. getcustomasset(fName) .. [["}]}]]
                writefile(cName, fontJson)
            end
            if isfile(cName) then
                return getcustomasset(cName)
            end
        end
        return nil
    end

    generalFontAsset = processFont(generalFontDataRaw, "phantom_general_font.ttf", "phantom_general_font.font", "PhantomGeneral")
    fortniteFontAsset = processFont(fortniteFontDataRaw, "phantom_fortnite_font.ttf", "phantom_fortnite_font.font", "PhantomFortnite")
end

local function GetCenterOrMouse()
    local cam = workspace.CurrentCamera
    if UserInputService.TouchEnabled then
        return Vector2.new(cam.ViewportSize.X / 2, cam.ViewportSize.Y / 2)
    else
        return UserInputService:GetMouseLocation()
    end
end

