local function getLuaFiles()
    local files = {}
    if listfiles and isfolder(scriptFolderName) then
        local success, result = pcall(listfiles, scriptFolderName)
        if success and type(result) == "table" then
            for _, file in ipairs(result) do
                local lowerFile = file:lower()
                if lowerFile:sub(-4) == ".lua" or lowerFile:sub(-4) == ".txt" then
                    local fileName = file:match("([^/\\]+)$") or file
                    table.insert(files, fileName)
                end
            end
        end
    end
    
    if #files == 0 then
        table.insert(files, "--")
    end
    return files
end

