local AuraInstances = {}
local AuraAssets = {
    starlight = "rbxassetid://134645216613107",
    heavenly = "rbxassetid://139300897520961",
    ribbon = "rbxassetid://132069507632161",
    sakura = "rbxassetid://81755778619404",
    angel = "rbxassetid://97658130917593",
    wind = "rbxassetid://80694081850877",
    flow = "rbxassetid://119913533725648",
    star = "rbxassetid://73754563740680"
}
local AuraCache = {}

local function clearAura()
    for _, obj in pairs(AuraInstances) do
        if obj and obj.Parent then obj:Destroy() end
    end
    table.clear(AuraInstances)
end

local function getTargetPart(char, partName)
    if char:FindFirstChild(partName) then
        return char:FindFirstChild(partName)
    end
    
    if partName == "Torso" then return char:FindFirstChild("UpperTorso") or char:FindFirstChild("HumanoidRootPart") end
    if partName == "Left Arm" then return char:FindFirstChild("LeftUpperArm") or char:FindFirstChild("LeftHand") end
    if partName == "Right Arm" then return char:FindFirstChild("RightUpperArm") or char:FindFirstChild("RightHand") end
    if partName == "Left Leg" then return char:FindFirstChild("LeftUpperLeg") or char:FindFirstChild("LeftFoot") end
    if partName == "Right Leg" then return char:FindFirstChild("RightUpperLeg") or char:FindFirstChild("RightFoot") end
    
    return char:FindFirstChild("HumanoidRootPart")
end

local function applyEffects(char)
    clearAura()
    if not Toggles.EnableAura.Value or not char then return end

    local baseColor = Options.AuraColor.Value
    local colorSeq = ColorSequence.new(baseColor)
    local selectedAuras = Options.AuraType.Value

    if type(selectedAuras) == "string" then
        selectedAuras = {[selectedAuras] = true}
    end

    for auraName, isSelected in pairs(selectedAuras) do
        if isSelected and AuraAssets[auraName] then
            if not AuraCache[auraName] then
                local success, result = pcall(function()
                    return game:GetObjects(AuraAssets[auraName])[1]
                end)
                if success and result then
                    AuraCache[auraName] = result
                else
                    Library:Notify("Failed to load aura: " .. auraName, 3)
                    continue
                end
            end

            local auraModel = AuraCache[auraName]
            if auraModel then
                for _, auraPart in ipairs(auraModel:GetChildren()) do
                    local charPart = getTargetPart(char, auraPart.Name)
                    
                    if charPart and charPart:IsA("BasePart") then
                        local effects = auraPart:GetChildren()
                        for _, effect in ipairs(effects) do
                            local clonedEffect = effect:Clone()
                            clonedEffect.Name = "PhantomAura_" .. auraName
                            clonedEffect.Parent = charPart
                            table.insert(AuraInstances, clonedEffect)
                            
                            local instancesToColor = clonedEffect:GetDescendants()
                            table.insert(instancesToColor, clonedEffect)
                            
                            for _, inst in ipairs(instancesToColor) do
                                if inst:IsA("PointLight") then
                                    inst.Color = baseColor
                                elseif inst:IsA("ParticleEmitter") or inst:IsA("Beam") or inst:IsA("Trail") then
                                    inst.Color = colorSeq
                                end
                            end
                        end
                    end
                end
            end
        end
    end
end

Toggles.EnableAura:OnChanged(function()
    if Toggles.EnableAura.Value then applyEffects(LocalPlayer.Character) else clearAura() end
end)

Options.AuraType:OnChanged(function()
    if Toggles.EnableAura.Value then applyEffects(LocalPlayer.Character) end
end)

Options.AuraColor:OnChanged(function()
    if Toggles.EnableAura.Value then applyEffects(LocalPlayer.Character) end
end)

LocalPlayer.CharacterAdded:Connect(function(char)
    task.wait(1)
    if Toggles.EnableAura.Value then applyEffects(char) end
end)

