        return
    end
    originalNotify(self, Text, Time)
end

Library.NotificationArea.ChildAdded:Connect(function(child)
    if child:IsA("Frame") then
        task.wait() 
        if Options.NotifTransparency then
            local Value = Options.NotifTransparency.Value
            child.BackgroundTransparency = Value
            for _, c in ipairs(child:GetChildren()) do
                if c:IsA("Frame") then
                    c.BackgroundTransparency = Value
                    for _, innerC in ipairs(c:GetChildren()) do
                        if innerC:IsA("Frame") then 
                            innerC.BackgroundTransparency = Value 
                        end
                    end
                end
            end
        end
    end
end)

