                Library:UpdateBlur()
            end
        })
        
        BackgroundTab:AddSlider('BlurSize', { 
            Text = 'Blur Strength', 
            Default = 15, 
            Min = 0, 
            Max = 50, 
            Rounding = 0,
            Callback = function(Value)
                Library.BlurSize = Value
                if Library.UseBlur and Library.Toggled then
                    Library.BlurEffect.Size = Value
                end
            end
        })

        BackgroundTab:AddDivider()

        BackgroundTab:AddToggle('WireframeDrag', { 
            Text = 'Wireframe Dragging', 
