local LoadBtn = LuaBox:AddButton({
    Text = 'load',
    Func = function()
        local selected = Options.SelectedLuaFile.Value
        if selected and selected ~= "--" then
            if not Toggles.AllowRisky.Value then
                Library:Notify("Please check 'allow risky' to execute.", 3)
                return
            end
            
            local filePath = scriptFolderName .. "/" .. selected
            if isfile and isfile(filePath) then
                local success, err = pcall(function()
                    loadstring(readfile(filePath))()
                end)
                if not success then
                    Library:Notify("Failed to load script: " .. tostring(err), 5)
                end
            end
        end
    end
})

