local prefix = "                " 
local fullText = "phantom.bin - discord.gg/8h9hDgbzUV"
local currentIndex = 0
local isTyping = true
local textUpdateTimer = 0

local textUpdateDelay = 0.05
local pauseDuration = 1

local TitleAnimConn
TitleAnimConn = RunService.Heartbeat:Connect(function(dt)
    if Library.Unloaded then
        TitleAnimConn:Disconnect()
        return
    end

    textUpdateTimer = textUpdateTimer + dt
    if textUpdateTimer >= textUpdateDelay then
        textUpdateTimer = 0
        
        if isTyping then
            currentIndex = currentIndex + 1
            if currentIndex >= #fullText then
                currentIndex = #fullText
                isTyping = false
                textUpdateTimer = -pauseDuration
            end
        else
            currentIndex = currentIndex - 1
            if currentIndex <= 0 then
                currentIndex = 0
                isTyping = true
                textUpdateTimer = -(pauseDuration / 2)
            end
        end
        
        local currentText = string.sub(fullText, 1, currentIndex)
        local hex = "FFFFFF"
        if Options.AccentColor then
            hex = Options.AccentColor.Value:ToHex()
        end
        
        Window:SetWindowTitle(prefix .. '<font color="#' .. hex .. '">' .. currentText .. '</font>')
    end
end)

local SKIN_ENABLED = false
local skinConnection = nil
local originalSkinBackup = nil
_G.SELECTED_SKIN = '62536494'

local function saveOriginalSkin()
    local char = LocalPlayer.Character
    if not char then return end
    local head = char:WaitForChild("Head", 10)
    if not head then return end

    originalSkinBackup = {
        accessories = {},
        shirt = nil,
        pants = nil,
        bodyColors = nil,
        face = nil,
        headMesh = nil,
    }

    for _, v in pairs(char:GetChildren()) do
        if v.Name == "ToxicHorns_Persistent" then continue end
        if v:IsA("Accessory") then
            table.insert(originalSkinBackup.accessories, v:Clone())
        elseif v:IsA("Shirt") then
            originalSkinBackup.shirt = v:Clone()
        elseif v:IsA("Pants") then
            originalSkinBackup.pants = v:Clone()
        elseif v:IsA("BodyColors") then
            originalSkinBackup.bodyColors = v:Clone()
        end
    end

    local face = head:FindFirstChild("face")
    if face then
        originalSkinBackup.face = face:Clone()
    end

    local mesh = head:FindFirstChildOfClass("SpecialMesh")
    if mesh then
        originalSkinBackup.headMesh = mesh:Clone()
    end
end

local function restoreOriginalSkin()
    if not originalSkinBackup then return end
    
    local char = LocalPlayer.Character
    if not char then return end
    local head = char:WaitForChild("Head", 10)
    if not head then return end

    for _, v in pairs(char:GetChildren()) do
        if v.Name == "ToxicHorns_Persistent" then continue end
        if v:IsA("Accessory") or v:IsA("Shirt") or v:IsA("Pants") or v:IsA("BodyColors") then
            v:Destroy()
        end
    end
    if head:FindFirstChild("face") then head.face:Destroy() end

    for _, acc in pairs(originalSkinBackup.accessories) do
        local newAcc = acc:Clone()
        newAcc.Parent = char
        local handle = newAcc:FindFirstChild("Handle")
        if handle then
            handle.CanCollide = false
            local att = handle:FindFirstChildOfClass("Attachment")
            if att then
                local targetAtt = char:FindFirstChild(att.Name, true)
                if targetAtt then
                    handle.CFrame = targetAtt.WorldCFrame * att.CFrame:Inverse()
                    local w = Instance.new("WeldConstraint")
                    w.Part0 = handle
                    w.Part1 = targetAtt.Parent
                    w.Parent = handle
                end
            end
        end
    end

    if originalSkinBackup.shirt then originalSkinBackup.shirt:Clone().Parent = char end
    if originalSkinBackup.pants then originalSkinBackup.pants:Clone().Parent = char end
    if originalSkinBackup.bodyColors then originalSkinBackup.bodyColors:Clone().Parent = char end

    if originalSkinBackup.face then
        local newFace = originalSkinBackup.face:Clone()
        newFace.Parent = head
    end

    if originalSkinBackup.headMesh then
        local existingMesh = head:FindFirstChildOfClass("SpecialMesh")
        if existingMesh then existingMesh:Destroy() end
        originalSkinBackup.headMesh:Clone().Parent = head
    end

    originalSkinBackup = nil
end

_G.applySkin = function(targetId)
    local char = LocalPlayer.Character
    if not char then return end
    local head = char:WaitForChild("Head", 10)
    if not head then return end

    local idNum = tonumber(targetId)
    if not idNum then 
        Library:Notify("Invalid User ID!", 3)
        return 
    end

    for _, v in pairs(char:GetChildren()) do
        if v.Name == "ToxicHorns_Persistent" then continue end
        if v:IsA("Accessory") or v:IsA("Shirt") or v:IsA("Pants") or v:IsA("BodyColors") then
            v:Destroy()
        end
    end
    if head:FindFirstChild("face") then head.face:Destroy() end

    local success, err = pcall(function()
        local appearance = Players:GetCharacterAppearanceAsync(idNum)
        for _, item in pairs(appearance:GetChildren()) do
            if item:IsA("Shirt") or item:IsA("Pants") or item:IsA("BodyColors") then
                item.Parent = char
            elseif item:IsA("Accessory") then
                task.spawn(function()
                    local newItem = item:Clone()
                    newItem.Parent = char
                    local handle = newItem:FindFirstChild("Handle")
                    if handle then
                        handle.CanCollide = false
                        local att = handle:FindFirstChildOfClass("Attachment")
                        if att then
                            local targetAtt = char:FindFirstChild(att.Name, true)
                            if targetAtt then
                                handle.CFrame = targetAtt.WorldCFrame * att.CFrame:Inverse()
                                local w = Instance.new("WeldConstraint")
                                w.Part0 = handle
                                w.Part1 = targetAtt.Parent
                                w.Parent = handle
                            end
                        end
                    end
                end)
            elseif item:IsA("Decal") and (item.Name == "face" or item.Texture:find("rbxassetid")) then
                item.Name = "face"
                item.Parent = head
            elseif item:IsA("SpecialMesh") and item.MeshType == Enum.MeshType.Head then
                local myMesh = head:FindFirstChildOfClass("SpecialMesh") or Instance.new("SpecialMesh", head)
                myMesh.MeshId = item.MeshId
                myMesh.TextureId = item.TextureId
                myMesh.Scale = item.Scale
            end
        end
    end)
    
    if not success then
        Library:Notify("Failed to load skin. ID might be wrong or rate limited.", 3)
    end
end

Toggles.SkinToggle:OnChanged(function()
    SKIN_ENABLED = Toggles.SkinToggle.Value
    if SKIN_ENABLED then
        saveOriginalSkin()
        _G.applySkin(_G.SELECTED_SKIN)
        if skinConnection then skinConnection:Disconnect() end
        skinConnection = LocalPlayer.CharacterAdded:Connect(function(char)
            char:WaitForChild("HumanoidRootPart")
            char:WaitForChild("Head")
            char:WaitForChild("Humanoid")
            local humanoid = char:FindFirstChildOfClass("Humanoid")
            if humanoid then
                repeat task.wait() until humanoid:GetState() ~= Enum.HumanoidStateType.None
            end
            task.wait(0.5)
            if SKIN_ENABLED and char.Parent then
                saveOriginalSkin()
                _G.applySkin(_G.SELECTED_SKIN)
            end
        end)
    else
        restoreOriginalSkin()
        if skinConnection then
            skinConnection:Disconnect()
            skinConnection = nil
        end
    end
end)

local ITEM_ID_HORNS = 1744060292

local function UpdateHornsTransform()
    local char = LocalPlayer.Character
    if char and char:FindFirstChild("ToxicHorns_Persistent") then
        local acc = char["ToxicHorns_Persistent"]
        local handle = acc:FindFirstChildWhichIsA("BasePart") or acc:FindFirstChild("Handle")
        if handle then
            local weld = handle:FindFirstChildWhichIsA("Weld")
            if weld then
                weld.C0 = CFrame.new(Options.HornsOffsetX.Value, Options.HornsOffsetY.Value, Options.HornsOffsetZ.Value)
            end
            
            local mesh = handle:FindFirstChildWhichIsA("SpecialMesh")
            if mesh then
                if not mesh:GetAttribute("OriginalScale") then
                    mesh:SetAttribute("OriginalScale", mesh.Scale)
                end
                local origScale = mesh:GetAttribute("OriginalScale")
                mesh.Scale = origScale * Options.HornsScale.Value
            else
                if not handle:GetAttribute("OriginalSize") then
                    handle:SetAttribute("OriginalSize", handle.Size)
                end
                handle.Size = handle:GetAttribute("OriginalSize") * Options.HornsScale.Value
            end
        end
    end
end

local function EquipHorns()
    local character = LocalPlayer.Character
    if not character then return end
    local head = character:WaitForChild("Head", 3)
    if not head then return end
    
    if character:FindFirstChild("ToxicHorns_Persistent") then
        character["ToxicHorns_Persistent"]:Destroy()
    end

    if not Toggles.EnableToxicHorns.Value then return end

    task.spawn(function()
        local success, assets = pcall(function()
            return game:GetObjects("rbxassetid://" .. ITEM_ID_HORNS)
        end)

        if success and assets and assets[1] then
            local accessory = assets[1]
            accessory.Name = "ToxicHorns_Persistent"
            accessory.Parent = character

            local handle = accessory:FindFirstChildWhichIsA("BasePart") or accessory:FindFirstChild("Handle")
            if handle then
                local weld = Instance.new("Weld")
                weld.Name = "HornsWeld"
                weld.Part0 = handle
                weld.Part1 = head
                weld.C0 = CFrame.new(Options.HornsOffsetX.Value, Options.HornsOffsetY.Value, Options.HornsOffsetZ.Value) 
                weld.Parent = handle
                
                local mesh = handle:FindFirstChildWhichIsA("SpecialMesh")
                if mesh then
                    if not mesh:GetAttribute("OriginalScale") then
                        mesh:SetAttribute("OriginalScale", mesh.Scale)
                    end
                    local origScale = mesh:GetAttribute("OriginalScale")
                    mesh.Scale = origScale * Options.HornsScale.Value
                else
                    if not handle:GetAttribute("OriginalSize") then
                        handle:SetAttribute("OriginalSize", handle.Size)
                    end
                    handle.Size = handle:GetAttribute("OriginalSize") * Options.HornsScale.Value
                end
            end
        end
    end)
end

Toggles.EnableToxicHorns:OnChanged(function()
    if Toggles.EnableToxicHorns.Value then
        EquipHorns()
    else
        local char = LocalPlayer.Character
        if char and char:FindFirstChild("ToxicHorns_Persistent") then
            char["ToxicHorns_Persistent"]:Destroy()
        end
    end
end)

Options.HornsScale:OnChanged(UpdateHornsTransform)
Options.HornsOffsetX:OnChanged(UpdateHornsTransform)
Options.HornsOffsetY:OnChanged(UpdateHornsTransform)
Options.HornsOffsetZ:OnChanged(UpdateHornsTransform)

LocalPlayer.CharacterAdded:Connect(function(char)
    task.wait(1)
    if Toggles.EnableToxicHorns.Value then
        EquipHorns()
    end
end)

local SnowCloudInstance = nil
