local function GetHealthColor(hp, mhp)
    if mhp == 0 then return Color3.new(0, 1, 0) end
    local p = math.clamp(hp / mhp, 0, 1)
    return Color3.fromHSV(p * 0.33, 1, 1)
end

local function UpdateESP()
    local currentCam = workspace.CurrentCamera
    for player, esp in pairs(espObjects) do
        local character = player.Character
        local rootPart = character and character:FindFirstChild("HumanoidRootPart")
        local humanoid = character and character:FindFirstChild("Humanoid")
        
        local isTargetTeam = false
        if Toggles.ESPEnabled.Value then
            local teamMode = Options.ESPTargetTeam.Value
            if teamMode == 'All' then 
                isTargetTeam = true 
            elseif teamMode == 'Enemy' and player.Team ~= LocalPlayer.Team then
                isTargetTeam = true
            elseif teamMode == 'Teammates' and player.Team == LocalPlayer.Team then
                isTargetTeam = true
            end
        end
        
        if character and rootPart and humanoid and humanoid.Health > 0 and Toggles.ESPEnabled.Value and player ~= LocalPlayer and isTargetTeam then
            local rootPos, isVisible = currentCam:WorldToViewportPoint(rootPart.Position)
            
            if isVisible then
                local topPos = currentCam:WorldToViewportPoint(rootPart.Position + Vector3.new(0, 3, 0))
                local bottomPos = currentCam:WorldToViewportPoint(rootPart.Position - Vector3.new(0, 3.5, 0))
                
                local height = math.abs(topPos.Y - bottomPos.Y)
                local width = height / 1.5 
                
                esp.Container.Position = UDim2.new(0, rootPos.X - (width / 2), 0, topPos.Y)
                esp.Container.Size = UDim2.new(0, width, 0, height)
                
                if Toggles.BoxESP.Value then
                    esp.OuterBorder.Visible = true
                    esp.MiddleBorder.Visible = true
                    esp.InnerBorder.Visible = true
                    esp.MiddleStroke.Color = Options.BoxColor.Value
                else
                    esp.OuterBorder.Visible = false
                    esp.MiddleBorder.Visible = false
                    esp.InnerBorder.Visible = false
                end
                
                if Toggles.BoxFillESP.Value then
                    esp.Fill.Visible = true
                    esp.Fill.BackgroundColor3 = Options.BoxFillColor.Value
                else
                    esp.Fill.Visible = false
                end
                
                local fontSize = Options.ESPFontSize.Value
                
                if Toggles.ESPShowName.Value then
                    esp.NameLabel.Text = player.DisplayName
                    esp.NameLabel.TextColor3 = Options.NameColor.Value
                    esp.NameLabel.TextSize = fontSize
                    esp.NameLabel.Size = UDim2.new(0, 200, 0, fontSize)
                    esp.NameLabel.Visible = true
                else
                    esp.NameLabel.Visible = false
                end
                
                if Toggles.ESPShowDist.Value then
                    local dist = (currentCam.CFrame.Position - rootPart.Position).Magnitude
                    esp.DistLabel.Text = string.format("%.1fm", dist)
                    esp.DistLabel.TextColor3 = Options.DistColor.Value
                    esp.DistLabel.TextSize = fontSize
                    esp.DistLabel.Size = UDim2.new(0, 200, 0, fontSize)
                    esp.DistLabel.Visible = true
                else
                    esp.DistLabel.Visible = false
                end
                
                if Toggles.ESPShowHealth.Value then
                    esp.HealthBg.Visible = true
                    local healthPercent = math.clamp(humanoid.Health / humanoid.MaxHealth, 0, 1)
                    esp.HealthFill.Size = UDim2.new(1, 0, healthPercent, 0)
                    if Toggles.ESPCustomHealth.Value then
                        esp.HealthFill.BackgroundColor3 = Options.HealthColor.Value
                        esp.HealthText.TextColor3 = Options.HealthColor.Value
                    else
                        local hc = GetHealthColor(humanoid.Health, humanoid.MaxHealth)
                        esp.HealthFill.BackgroundColor3 = hc
                        esp.HealthText.TextColor3 = hc
                    end
                    esp.HealthText.Text = tostring(math.floor(humanoid.Health))
                    esp.HealthText.TextSize = fontSize - 2
                    esp.HealthText.Size = UDim2.new(0, 50, 0, fontSize - 2)
                    esp.HealthText.Position = UDim2.new(0, -2, 1 - healthPercent, 0)
                else
                    esp.HealthBg.Visible = false
                    esp.HealthText.Text = ""
                end
                
                local rightSideY = 0

                if Toggles.ESPShowWeapon.Value then
                    local equippedTool = character:FindFirstChildWhichIsA("Tool")
                    if equippedTool then
                        esp.WeaponText.Text = equippedTool.Name
                        esp.WeaponText.TextColor3 = Options.WeaponColor.Value
                        esp.WeaponText.TextSize = fontSize - 2
                        esp.WeaponText.Size = UDim2.new(0, 200, 0, fontSize - 2)
                        esp.WeaponText.Position = UDim2.new(1, 4, 0, rightSideY)
                        esp.WeaponText.Visible = true
                        rightSideY = rightSideY + (fontSize - 2) + 2
                    else
                        esp.WeaponText.Visible = false
                    end
                else
                    esp.WeaponText.Visible = false
                end
                
                if Toggles.ESPShowTeam.Value then
                    local teamName = player.Team and player.Team.Name or "None"
                    esp.TeamText.Text = teamName
                    esp.TeamText.TextColor3 = Options.TeamColor.Value
                    esp.TeamText.TextSize = fontSize - 2
                    esp.TeamText.Size = UDim2.new(0, 200, 0, fontSize - 2)
                    esp.TeamText.Position = UDim2.new(1, 4, 0, rightSideY)
                    esp.TeamText.Visible = true
                else
                    esp.TeamText.Visible = false
                end
                
                esp.Container.Visible = true
            else
                esp.Container.Visible = false
            end
            
            if Toggles.SkeletonESP.Value then
                local head = character:FindFirstChild("Head")
                local torso = character:FindFirstChild("Torso") or character:FindFirstChild("UpperTorso")
                local lArm = character:FindFirstChild("Left Arm") or character:FindFirstChild("LeftUpperArm")
                local rArm = character:FindFirstChild("Right Arm") or character:FindFirstChild("RightUpperArm")
                local lLeg = character:FindFirstChild("Left Leg") or character:FindFirstChild("LeftUpperLeg")
                local rLeg = character:FindFirstChild("Right Leg") or character:FindFirstChild("RightUpperLeg")

                if head and torso and lArm and rArm and lLeg and rLeg then
                    local points3D = {
                        head.CFrame.Position,
                        (torso.CFrame * CFrame.new(0, 1, 0)).Position,
                        (torso.CFrame * CFrame.new(0, -1, 0)).Position,
                        (lArm.CFrame * CFrame.new(0, 1, 0)).Position,
                        (lArm.CFrame * CFrame.new(0, -1, 0)).Position,
                        (rArm.CFrame * CFrame.new(0, 1, 0)).Position,
                        (rArm.CFrame * CFrame.new(0, -1, 0)).Position,
                        (lLeg.CFrame * CFrame.new(0, 1, 0)).Position,
                        (lLeg.CFrame * CFrame.new(0, -1, 0)).Position,
                        (rLeg.CFrame * CFrame.new(0, 1, 0)).Position,
                        (rLeg.CFrame * CFrame.new(0, -1, 0)).Position
                    }

                    local function connect(lineIdx, p1Idx, p2Idx)
                        local pos1, vis1 = currentCam:WorldToViewportPoint(points3D[p1Idx])
                        local pos2, vis2 = currentCam:WorldToViewportPoint(points3D[p2Idx])

                        if vis1 or vis2 then
                            esp.SkeletonLines[lineIdx].From = Vector2.new(pos1.X, pos1.Y)
                            esp.SkeletonLines[lineIdx].To = Vector2.new(pos2.X, pos2.Y)
                            esp.SkeletonLines[lineIdx].Color = Options.SkeletonColor.Value
                            esp.SkeletonLines[lineIdx].Visible = true
                        else
                            esp.SkeletonLines[lineIdx].Visible = false
                        end
                    end

                    connect(1, 1, 2)
                    connect(2, 2, 3)
                    connect(3, 2, 4)
                    connect(4, 4, 5)
                    connect(5, 2, 6)
                    connect(6, 6, 7)
                    connect(7, 3, 8)
                    connect(8, 8, 9)
                    connect(9, 3, 10)
                    connect(10, 10, 11)
                else
                    for _, line in ipairs(esp.SkeletonLines) do line.Visible = false end
                end
            else
                for _, line in ipairs(esp.SkeletonLines) do line.Visible = false end
            end
        else
            if espObjects[player] then
                if espObjects[player].Container then
                    espObjects[player].Container.Visible = false
                end
                if espObjects[player].SkeletonLines then
                    for _, line in ipairs(espObjects[player].SkeletonLines) do
                        line.Visible = false
                    end
                end
            end
        end
    end
end

Players.PlayerAdded:Connect(function(p) p.CharacterAdded:Connect(function() task.wait(1); createESP(p) end) end)
for _, p in pairs(Players:GetPlayers()) do if p ~= LocalPlayer then createESP(p); p.CharacterAdded:Connect(function() task.wait(1); createESP(p) end) end end

RunService:BindToRenderStep("PhantomOverlay", Enum.RenderPriority.Last.Value + 200, function(deltaTime)
    local currentCam = workspace.CurrentCamera
    local mouseLoc = GetCenterOrMouse()

    UpdateESP()

    if Toggles.TimeChanger.Value then 
        local timeVal = Options.TimeVal.Value
        Lighting.ClockTime = timeVal
        
        local sunIntensity = math.clamp(math.sin(math.pi * (timeVal - 6) / 12), 0, 1)
        Lighting.Brightness = 0.5 + (sunIntensity * 2.5) 

        if not Toggles.WorldVisuals.Value then
            local amb = 30 + (sunIntensity * 120) 
            Lighting.Ambient = Color3.fromRGB(amb, amb, amb)
            Lighting.OutdoorAmbient = Color3.fromRGB(amb, amb, amb)
        end
    end

    if Toggles.WorldVisuals.Value then
        local c = Options.WorldColor.Value
        Lighting.Ambient = c; Lighting.OutdoorAmbient = c; Lighting.ColorShift_Top = Color3.fromRGB(180, 120, 255)
        Lighting.FogColor = c; Lighting.FogStart = 0; Lighting.FogEnd = Options.FogDist.Value
        local cc = Lighting:FindFirstChild("PhantomCC") or Instance.new("ColorCorrectionEffect", Lighting)
        cc.Name = "PhantomCC"; cc.Enabled = true; cc.TintColor = c; cc.Saturation = 0.5; cc.Contrast = 0.1
    else
        local cc = Lighting:FindFirstChild("PhantomCC"); if cc then cc.Enabled = false end
    end

    if Toggles.EnableAtmosphere.Value then
        local atmo = Lighting:FindFirstChildOfClass("Atmosphere") or Instance.new("Atmosphere", Lighting)
        atmo.Name = "PhantomAtmosphere"
        local color = Options.AtmosphereColor.Value
        atmo.Color = color
        atmo.Decay = Color3.new(math.clamp(color.R - 0.15, 0, 1), math.clamp(color.G - 0.15, 0, 1), math.clamp(color.B - 0.15, 0, 1))
        atmo.Density = Options.AtmosphereDensity.Value
        atmo.Haze = Options.AtmosphereHaze.Value
        atmo.Glare = 0.5
        atmo.Offset = 0.25
    else
        local atmo = Lighting:FindFirstChild("PhantomAtmosphere")
        if atmo then atmo:Destroy() end
    end

    if Toggles.ResStretch.Value then currentCam.CFrame = currentCam.CFrame * CFrame.new(0, 0, 0, 1, 0, 0, 0, Options.ResFactor.Value, 0, 0, 0, 1) end

    if Toggles.CrosshairEnabled.Value then
        CH_ScreenGui.Enabled = true
        UserInputService.MouseIconEnabled = false 
        
        local basePos = mouseLoc
        
        if Toggles.CrosshairOnMuzzle and Toggles.CrosshairOnMuzzle.Value then
            local char = LocalPlayer.Character
            if char then
                local tool = char:FindFirstChildOfClass("Tool")
                if tool then
                    local muzzle = tool:FindFirstChild("Muzzle")
                    if muzzle then
                        local screenPos, onScreen = currentCam:WorldToViewportPoint(muzzle.Position)
                        if onScreen then
                            basePos = Vector2.new(screenPos.X, screenPos.Y)
                        end
                    end
                end
            end
        end

        local customTextSize = Options.CH_TextSize.Value
        local customTextOffset = Options.CH_TextOffset.Value

        CH_TextLabel.TextSize = customTextSize
        CH_Holder.Position = UDim2.fromOffset(basePos.X, basePos.Y)
        CH_TextLabel.Position = UDim2.fromOffset(basePos.X, basePos.Y + customTextOffset)
        
        if Toggles.HideCrosshairText.Value then
            CH_TextLabel.Visible = false
        else
            CH_TextLabel.Visible = true
            
            local tColor = Options.CH_TextColor.Value
            if Toggles.CH_RGBText.Value then
                tColor = Color3.fromHSV(tick() % 5 / 5, 1, 1)
            end
            
            CH_TextLabel.TextColor3 = tColor
            CH_TextLabel.Text = Options.CH_CustomText.Value
        end
        
        local barColor = Options.CH_BarColor.Value
        if Toggles.CH_RGBBar.Value then
            barColor = Color3.fromHSV(tick() % 5 / 5, 1, 1)
        end

        local outColor = Options.CH_OutlineColor.Value
        if Toggles.CH_RGBOutline.Value then
            outColor = Color3.fromHSV(tick() % 5 / 5, 1, 1)
        end
        
        -- Outline thickness update
        local strokeThickness = Options.CH_StrokeThickness.Value
        CH_TextStroke.Thickness = strokeThickness
        CH_TextStroke.Color = outColor
        
        CH_Top.BackgroundColor3 = barColor; CH_Top.Outline.Color = outColor; CH_Top.Outline.Thickness = strokeThickness
        CH_Bottom.BackgroundColor3 = barColor; CH_Bottom.Outline.Color = outColor; CH_Bottom.Outline.Thickness = strokeThickness
        CH_Left.BackgroundColor3 = barColor; CH_Left.Outline.Color = outColor; CH_Left.Outline.Thickness = strokeThickness
        CH_Right.BackgroundColor3 = barColor; CH_Right.Outline.Color = outColor; CH_Right.Outline.Thickness = strokeThickness
        
        local g = Options.CH_Gap.Value
        local maxLen = Options.CH_Length.Value
        local minLen = Options.CH_MinLength.Value
        local thickness = Options.CH_Thickness.Value
        local animSpeed = Options.CH_AnimSpeed.Value
        
        local ct = os.clock() * animSpeed
        local cycleDur = 2.0
        local alpha = animSpeed > 0 and (ct % cycleDur) / cycleDur or 0
        local currentRotation = easeHybrid(alpha) * 360
        local currentLength = minLen + (math.sin(alpha * math.pi) * (maxLen - minLen))
        
        CH_Holder.Rotation = currentRotation
        CH_Top.Position = UDim2.new(0.5, 0, 0.5, -g)
        CH_Bottom.Position = UDim2.new(0.5, 0, 0.5, g)
        CH_Left.Position = UDim2.new(0.5, -g, 0.5, 0)
        CH_Right.Position = UDim2.new(0.5, g, 0.5, 0)
        
        local sv = UDim2.new(0, thickness, 0, currentLength)
        CH_Top.Size = sv
        CH_Bottom.Size = sv
        
        local sh = UDim2.new(0, currentLength, 0, thickness)
        CH_Left.Size = sh
        CH_Right.Size = sh
    else
        CH_ScreenGui.Enabled = false
        UserInputService.MouseIconEnabled = true 
    end
end)

Library:OnUnload(function()
    RunService:UnbindFromRenderStep("PhantomOverlay")
    if TitleAnimConn then TitleAnimConn:Disconnect() end
    RemoveSnow()
    RemoveRain()
    clearAura()
    
    local char = LocalPlayer.Character
    if char and char:FindFirstChild("ToxicHorns_Persistent") then
        char["ToxicHorns_Persistent"]:Destroy()
    end
    restoreOriginalSkin()

    for _, esp in pairs(espObjects) do
        if esp.Container then esp.Container:Destroy() end
        if esp.SkeletonLines then
            for _, line in ipairs(esp.SkeletonLines) do
                line:Remove()
            end
        end
    end
    if ESPFolder then ESPFolder:Destroy() end
    if CH_ScreenGui then CH_ScreenGui:Destroy() end
    
    local atmo = Lighting:FindFirstChild("PhantomAtmosphere")
    if atmo then atmo:Destroy() end
    
    if voidSpamConnection then voidSpamConnection:Disconnect() end
    if skinConnection then skinConnection:Disconnect() end
    UserInputService.MouseIconEnabled = true
end)
